export const docsGuide = {"categories":[{"title":"Getting started","stories":[{"id":"create-identity","title":"Create your identity","introHtml":"<p>Register a WebAuthn passkey — no password, ever. Your OpenApe ID becomes the DDISA authority for your identity: every Service Provider logs you in via DNS-discovered SSO without ever seeing a credential.</p>\n","steps":[{"title":"Open OpenApe ID","html":"The landing page asks for nothing but your email. Click <strong>Create account</strong> to start.","shot":"/docs/screenshots/create-identity/01-landing.png"},{"title":"Request your registration link","html":"Enter your email — OpenApe ID sends you a one-time registration link.","shot":"/docs/screenshots/create-identity/02-request-link.png"},{"title":"Register your passkey","html":"The link opens the passkey ceremony. Your device (Touch ID, Windows Hello, a security key) creates the credential — in this E2E run a virtual authenticator answers headlessly.","shot":"/docs/screenshots/create-identity/03-register-passkey.png"},{"title":"Done — you are signed in","html":"That&#39;s the whole sign-up: one passkey, no password to remember or leak.","shot":"/docs/screenshots/create-identity/04-registered.png"}]}]},{"title":"Account","stories":[{"id":"account-dashboard","title":"Your account dashboard","introHtml":"<p>Your dashboard is home base for your identity. Passkeys, SSH keys, agents, permissions, delegations and connected services each have their own page, so you go straight to the one you need.</p>\n","steps":[{"title":"Open your dashboard","html":"Once you&#39;re signed in, the dashboard brings together everything tied to your identity — passkeys, SSH keys, agents, permissions, delegations and connected services. Choose an area to open it.","shot":"/docs/screenshots/account-dashboard/01-dashboard.png"},{"title":"Manage your passkeys","html":"Open <strong>Passkeys</strong> to manage how you sign in — add a new device, or remove one you no longer use.","shot":"/docs/screenshots/account-dashboard/02-passkeys.png"},{"title":"Manage your SSH keys","html":"<strong>SSH keys</strong> holds the public keys for <em>Sign in with SSH Key</em>. Paste a key to add it, or remove one you&#39;ve retired.","shot":"/docs/screenshots/account-dashboard/03-ssh-keys.png"},{"title":"Review connected services","html":"<strong>Connected services</strong> lists the apps you&#39;ve signed in to with your OpenApe ID. Revoke one and you&#39;ll be asked to approve it again next time. Apps acting for you at <em>another</em> service live under <strong>Delegations</strong>.","shot":"/docs/screenshots/account-dashboard/04-connected-services.png"}]}]},{"title":"Agents","stories":[{"id":"agent-identities","title":"Your agent identities","introHtml":"<p>Agents are first-class identities under your account: the IdP mints them a DDISA email and you stay in control.</p>\n","steps":[{"title":"Open Agents at your IdP","html":"Every agent spawned from your nests appears here with its own <code>…@id.openape.ai</code> identity — inspect it, or revoke it independently of your own keys.","shot":"/docs/screenshots/agent-identities/01-agents.png"}]}]}]}
